#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_initial_state() {
        let sm = FileLockStateMachine::new();
        assert_eq!(sm.current_state(), FileLockState::Active);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = FileLockStateMachine::from_state(FileLockState::Active);
        assert!(sm.can_transition(FileLockTransition::Expire));
        let result = sm.transition(FileLockTransition::Expire);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), FileLockState::Expired);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = FileLockStateMachine::from_state(FileLockState::Expired);
        // Expire is not valid from Expired state
        let result = sm.transition(FileLockTransition::Expire);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: FileLockState = "active".parse().unwrap();
        assert_eq!(state, FileLockState::Active);
    }

    #[test]
    fn test_available_transitions() {
        let sm = FileLockStateMachine::new();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
